var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"가장 먼저 공략한 대균열은 캄파멘토.","JPN":"最初に攻略した大亀裂はカンパメント。","ENG":"The first Grand Dimension Crevice I went to was in Campamento.","TWN":"最先攻略的大峽谷是坎帕門托。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_CA_SWAN","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이곳은 탐험대로 위장하여 대균열에 접근할 수 있었죠.","JPN":"ここには探検隊として偽装し、大亀裂に接近することができました。","ENG":"I was able to approach the Grand Dimension Crevice by disguising myself as an expedition member.","TWN":"我依靠著偽裝成探險隊接近了那裡。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_CA_SWAN","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"다음으로는 화보 촬영을 명분으로 방문한 프론트 베이.","JPN":"次は写真集の撮影という名目で訪問したフロントベイ。","ENG":"After, I visited Front Bay under the pretext of a photoshoot.","TWN":"接下來以拍攝畫報為名訪問了前灣。"},"stage":{"bg":"FRONTBAY_IN","bgm":"THEMA_CA_SWAN","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"해저 깊은 곳에 있는 대균열에 거울 조각을 끼워 넣는 건 쉬운 일이 아니었습니다.","JPN":"海底深く腰掛けている大亀裂に鏡の破片を仕込むのは、決して容易ではありませんでした。","ENG":"It wasn't easy placing a mirror fragment into a Grand Dimension Crevice deep under the sea.","TWN":"將鏡子碎片嵌入深海中的大峽谷並非易事……"},"stage":{"bg":"FRONTBAY_IN","bgm":"THEMA_CA_SWAN","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"세번째는 그라운드 원.","JPN":"三つ目はグラウンド・ワン。","ENG":"The third was in Ground One.","TWN":"第三個是G1。"},"stage":{"bg":"GROUND_ONE","bgm":"THEMA_CA_SWAN","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"예상치 못한 변수가 발생했지만, 결국 각본대로 대균열에 조각을 끼워둘 수 있었어요.","JPN":"予想外のトラブルが発生しましたが、私の脚本に狂いはありませんでした。無事大亀裂に破片を仕込むことに成功。","ENG":"Although unexpected variables arose, I was ultimately able to place a fragment into the Grand Dimension Crevice, all according to the script.","TWN":"雖然出現了意想不到的變數，但最終還是按照劇本將碎片嵌入了大峽谷。"},"stage":{"bg":"GROUND_ONE","bgm":"THEMA_CA_SWAN","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"……챔버.","JPN":"……チェンバー。","ENG":"...Chamber.","TWN":"……強巴."},"stage":{"bg":"CHAMBER","bgm":"THEMA_CA_SWAN","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"수시로 대균열 탐사대가 결성되는 이곳은 비교적 다른 곳보다 수월한 편이었죠.","JPN":"時々大亀裂の探査部隊が結成されるここは、他のところより比較的簡単でした。","ENG":"It was comparatively easier as expedition teams were formed frequently.","TWN":"這裡經常組建大峽谷探險，相對其他地方來說比較輕鬆。"},"stage":{"bg":"CHAMBER","bgm":"THEMA_CA_SWAN","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"다섯 번째 대균열은 샤레이드.","JPN":"五つ目の大亀裂はシャレード。","ENG":"The fifth was in Charade.","TWN":"第五是查雷德。"},"stage":{"bg":"CHARADE","bgm":"THEMA_CA_SWAN","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"건틀렛 리그가 진행 중이었던 이곳에 있는 동안에는 꽤 많은 일이 있었답니다.","JPN":"ガントレットリーグが進行中だったこの場所にいる間は、結構多くの出来事がありました。","ENG":"A lot had happened while the Gauntlet League was ongoing.","TWN":"在聖鎧聯賽進行期間，這裡發生了很多事情。"},"stage":{"bg":"CHARADE","bgm":"THEMA_CA_SWAN","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"결과적으로는 하베스터의 힘을 빌려, 거울 조각을 끼워 넣었을 수 있었어요.","JPN":"結果的にはハーベスターの力を借りて、鏡の破片を仕込むことができました。","ENG":"In the end, I was able to place a mirror fragment in with the help of Harvester.","TWN":"最終借助收割者的力量，成功嵌入了鏡子碎片。"},"stage":{"bg":"CHARADE","bgm":"THEMA_CA_SWAN","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그리고 마지막 로터스의 대균열…….","JPN":"そして最後、ロータスの大亀裂……","ENG":"And the last was Lotus.","TWN":"然後是最後的洛德斯……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CA_SWAN","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"모든 것은 각본대로.","JPN":"すべては脚本どおりに。","ENG":"Everything according to the script.","TWN":"一切都將按照劇本進行。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CA_SWAN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"저는 전 세계 여섯 군데의 대균열에 클리파 차원과 연결된 거울 조각을 끼워 넣었습니다.","JPN":"私は全世界、六か所の大亀裂にクリファ次元に繋がる鏡の破片を仕込みました。","ENG":"I have successfully placed a mirror fragment in all six Grand Dimension Crevices around the world that are connected to the Qlipha Dimension.","TWN":"我在全世界六個大峽谷中嵌入了與逆卡巴拉次元相連的鏡片。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CA_SWAN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"코핀 오브 타기리온의 <color=#ffd34c>마지막 열쇠</color>가 해방된 지금.","JPN":"コフィン・オブ・タギリオンの<color=#ffd34c>最後の鍵</color>が解放された今。","ENG":"And now, with Coffin of Thagirion's <color=#ffd34c>last key</color> being liberated...","TWN":"塔基里翁之棺<color=#ffd34c>最後的鑰匙</color>已經解放。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CA_SWAN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그림자 전당 내부로부터 방출되는 당신의 클리파 타입 허수 에너지는…….","JPN":"影の殿堂の内部から放出されるあなたのクリファタイプ虚数エネルギーは……","ENG":"Your Qlipha-type Imaginary Energy radiating from within the Shadow Palace...","TWN":"從暗影殿堂內部釋放出的你的神聖虛空能量……"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CA_SWAN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"세계 각지의 대균열과 연결된 거울 조각과 공명하여, 전 세계로 확산되겠죠.","JPN":"世界各地の大亀裂と繋がった鏡の破片と共鳴し、全世界へと拡散するでしょう。","ENG":"It will resonate with the mirror fragments linked to the Grand Dimension Crevices around the world and start to spread.","TWN":"將與連接世界各地大峽谷的鏡片共鳴，擴散到全世界。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CA_SWAN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"암군이여. 계약은 지켰습니다.","JPN":"暗君よ。契約は守りました。","ENG":"Oh, Ignorant Monarch. I have kept my end of the contract.","TWN":"昏君啊。我遵守了契約。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CA_SWAN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L42_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그리고 마침내 무대는 클라이맥스에 다다르겠죠.","JPN":"そしてついに舞台はクライマックスを迎えるでしょう。","ENG":"And now, the performance will soon reach its climax.","TWN":"現在，舞台即將迎來高潮。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CA_SWAN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"……그 끝이 비극일지라도.","JPN":"……その終わりが悲劇であっても。","ENG":"...Even if the end will be tragic.","TWN":"……即使它的結局是悲劇。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CA_SWAN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L47_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>로터스, 그림자 전당 내부로부터 특이 에너지 확산 관측.</color>","JPN":"<color=#ffd34c>ロータス、影の殿堂の内部より特異エネルギーの拡散を観測。</color>","ENG":"<color=#ffd34c>In Lotus, detecting abnormal energy spreading from Shadow Palace.</color>","TWN":"<color=#ffd34c>洛德斯，在暗影殿堂內部觀察到特殊的能量擴散。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>분석 결과: 신성 클리파 타입- 타기리온.</color>","JPN":"<color=#ffd34c>分析結果：神聖クリファタイプ-タギリオン。</color>","ENG":"<color=#ffd34c>Analysis results: Divinity Qlipha Type- Thagirion.</color>","TWN":"<color=#ffd34c>分析結果：神聖逆卡巴拉類型-塔基里翁。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>마왕 강림 및 현실 차원계면 붕괴까지… 앞으로 약 30분.</color>","JPN":"<color=#ffd34c>魔王降臨および現実の次元界面の崩壊まで……残りおよそ30分。</color>","ENG":"<color=#ffd34c>Demon Lord's resurrection and the collapse of Normalside's dimension surface in... approximately 30 minutes.</color>","TWN":"<color=#ffd34c>距離魔王降臨與現世次元邊界瓦解……還剩大約30分鐘。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"COUNTER_NPC_M_NULL","text":{"KOREA":"저게… 대체 뭐야?","JPN":"あれって……いったい何だ？","ENG":"What... is that?","TWN":"那到底是……什麼？"},"stage":{"bg":"MS_1203","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"COUNTER_NPC_M_NULL","text":{"KOREA":"지금 사람들이 하늘로 솟구치고 있는 건가?","JPN":"人が空へと浮かび上がっているのか？","ENG":"Are people floating up to the sky?","TWN":"人飄到天上了？"},"stage":{"bg":"MS_1203","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"샤레이드 방어 작전에 참여하고 있는 전 태스크포스 병력들에게 전파한다.","JPN":"シャレードの防御作戦に参加している全タスクフォース兵に伝える。","ENG":"Attention all TASKFORCEs participating in the Charade Defense Operation.","TWN":"所有參與查雷德防禦戰的特遣勢力人員請注意。"},"stage":{"bg":"MS_1203","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>이것은 관리국에서 시민 여러분들께 송출하는 행동 요령 안내입니다.</color>","JPN":"<color=#ffd34c>これは管理局から市民の皆様に伝える、行動指針のご案内です。</color>","ENG":"<color=#ffd34c>This is a safety announcement for citizens from the Administration.</color>","TWN":"<color=#ffd34c>這是管理局向各位市民發送的行動要領。</color>"},"stage":{"bg":"MS_1203","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"현 시간부로 절대 하늘을 쳐다보지 마라.","JPN":"今から絶対に空を見上げるな。","ENG":"As of this moment, do not look up at the sky.","TWN":"從現在起絕對不要抬頭看天空。"},"stage":{"bg":"MS_1203","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"어떤 외침이나 부름이 느껴져도 고개를 들어선 안된다.","JPN":"どんな叫び声や呼ぶ声が聞こえても頭を上げてはならない。","ENG":"No matter what you hear, you must not raise your head.","TWN":"不管聽到怎樣的呼喊或聲音也絕不要抬頭。"},"stage":{"bg":"MS_1203","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>가능한 실내에 머무르시고 실외에서는 절대 하늘을 바라보지 마십시오.</color>","JPN":"<color=#ffd34c>できる限り室内にいて、屋外では決して空を見上げないようにしてください。</color>","ENG":"<color=#ffd34c>Stay indoors as much as possible, and never look up at the sky when outdoors.</color>","TWN":"<color=#ffd34c>請儘量待在室內，在室外絕對不要抬頭看天空。</color>"},"stage":{"bg":"DOCK_NIGHT","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"하늘을 보는 순간 빨려들어가듯 중력을 잃고 하늘로 부상하게 된다고 한다.","JPN":"空を見た瞬間吸い込まれるように重力を失い、浮かび上がっていく。","ENG":"They say looking up will make you lose gravity and get sucked up into the sky.","TWN":"如果抬頭望天空，就會失去重力漂浮到天上。"},"stage":{"bg":"DOCK_NIGHT","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"일종의 침식현상이라 생각하면 되겠지만, 이 현상은 이터니움실드로도 막을 수 없다.","JPN":"一種の侵食現象であるが、これはエタニウムシールドでも防げない。","ENG":"I think it's a type of Counterside Effect, but it can't be blocked with the Eternium shield.","TWN":"可以把它看作是一種侵蝕現象，但是用永恆之金防護網也無法阻擋。"},"stage":{"bg":"DOCK_NIGHT","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>안전을 위해 절대 대피소를 벗어나지 마시고, 관리국의 지침을 따라주십시오.</color>","JPN":"<color=#ffd34c>安全のため決して避難所を離れず、管理局の行動指針に従ってください。</color>","ENG":"<color=#ffd34c>For your safety, follow the Administration's guidelines and do not leave the shelter.</color>","TWN":"<color=#ffd34c>為保安全，千萬不要離開避難所，請聽從管理局的指示。</color>"},"stage":{"bg":"DOCK_NIGHT","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>해당 지침은 경보해제시까지 유효합니다.</color>","JPN":"<color=#ffd34c>この行動指針は警報が解除されるまで有効です。</color>","ENG":"<color=#ffd34c>The guidelines will remain in effect until the disaster alert is lifted.</color>","TWN":"<color=#ffd34c>該指令將持續到警報解除。</color>"},"stage":{"bg":"DOCK_NIGHT","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"이상. 무사히 살아서 다시 만나지.","JPN":"以上。無事に生きてまた会おう。","ENG":"Over and out. We'll meet again after we survive.","TWN":"就這樣，我們活著再見面吧。"},"stage":{"bg":"BLACK","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"갑자기 뭐야? 이런 불길한 경보는 처음 듣는데?","JPN":"いきなり何？　こんな不吉な警報は始めて聞くよ？","ENG":"What's that? I've never heard an ominous alarm like this before.","TWN":"怎麼回事？從沒聽過這麼恐怖的警報？"},"stage":{"bg":"CORRIDOR","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_SIREN"},{"id":"L26_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"아케론의 시스템이 침식파를 감지한 겁니다.","JPN":"アケロンのシステムが侵食波を感知したんです。","ENG":"Acheron's systems have detected Corruption rays.","TWN":"黃泉系統感應到侵蝕波了。"},"stage":{"bg":"CORRIDOR","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"침식파? 우주에도 그런 게 있었어?","JPN":"侵食波？　宇宙にもそんなものがあったの？","ENG":"Corruption ray? That's a thing in space too?","TWN":"侵蝕波？宇宙也有這種東西？"},"stage":{"bg":"CORRIDOR","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"서둘러, 발키리! 아케론에서 탈옥을 눈치 채고 승강궤도를 끊어버릴 지도 몰라!","JPN":"急いで、ヴァルキリー！　アケロンが脱獄に気づいて昇降レールを切ってしまうかもしれない！","ENG":"Hurry up, Valkyrie! They might catch wind of our escape and cut us off from the orbit!","TWN":"快點，女武神！要是越獄被黃泉發現了電梯會被攔截！"},"stage":{"bg":"CORRIDOR","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"야! 거기서 뭘 하고 있는…!","JPN":"こら！　そこで何してる……！","ENG":"Hey! What are you doing over the–!","TWN":"喂！你在那裡幹什麼……！"},"stage":{"bg":"CORRIDOR","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"뭐야? 저건?","JPN":"何？　あれ？","ENG":"Huh? What in the world...?","TWN":"那是什麼？"},"stage":{"bg":"MS_1204","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"…지상에 저런 큰 대균열이 있었나?","JPN":"……地上にあれほど大きい大亀裂があったっけ？","ENG":"...Was there always a Grand Dimension Crevice that big down there?","TWN":"……地面上怎麼有那麼巨大的大峽谷？"},"stage":{"bg":"MS_1204","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"저 곳이라면…. 그림자 전당과 이어져 있겠군.","JPN":"あそこなら……影の殿堂と繋がっているはず。","ENG":"That location... It must be connected to the Shadow Palace.","TWN":"那裡……是通往暗影殿堂的地方。"},"stage":{"bg":"MS_1204","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"방주의 봉인이 풀린 거다.","JPN":"箱舟の封印が解かれたのだ。","ENG":"The Ark's seal has been broken.","TWN":"方舟的封印被解除了。"},"stage":{"bg":"MS_1204","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"허어.","JPN":"へえっ。","ENG":"Huh.","TWN":"唉。"},"stage":{"bg":"MS_1204","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L40_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"누구 작품인지, 타이밍 한 번 기가 막히구만.","JPN":"誰がやったんだろ、タイミングがバッチリだね。","ENG":"I don't know whose work this is, but the timing is just perfect.","TWN":"不知道是誰一手策劃的，時機掌握得真是巧妙。"},"stage":{"bg":"MS_1204","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"끝났군요.","JPN":"終わりましたね。","ENG":"It is over.","TWN":"結束了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"타기리온이 현실을 완전히 잠식하면, 당신이 지금껏 해온 노력은 모두 허사가 되겠죠.","JPN":"タギリオンが現実を完全に侵食すると、今までのあなたの努力は全部無駄になるでしょう。","ENG":"Once Thagirion completely consumes this world, everything you have done up until this moment will be in vain.","TWN":"一旦塔基里翁徹底吞噬了現實，你所有的努力都將付諸東流。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"감상이 어떠신가요?","JPN":"どんなお気持ちですか？","ENG":"How does that make you feel?","TWN":"不知你有何感想？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"클리파 차원을 틀어막는 방주의 에너지는 애초부터 무한하지 않았네.","JPN":"クリファ次元を封じ込めている箱舟のエネルギーは最初から無限ではなかったのだ。","ENG":"The Ark's energy that's blocking the Qlipha Dimension has never been infinite.","TWN":"方舟用來阻止逆卡巴拉次元的能量本來就不是無限的。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"언젠가 닥칠 일이란 건 알았지만, 조금 이르다는 감은 있군.","JPN":"いつかはこうなると思っていたが、少し早い気がするな。","ENG":"This was going to happen sooner or later, but it feels a little earlier than I had expected.","TWN":"我早就料到她的回歸，但僅是比我的預期有些稍早而已。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"저런 꼴을 보고서도 아직 포기를 못한 건가요?","JPN":"あのありさまを見てもまだ、諦めがつかないのですか？","ENG":"You still have hope, after seeing what has happened?","TWN":"看到這些還沒有放棄嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"할 수 있는 데까진 해봐야지.","JPN":"やれるところまではやってみるさ。","ENG":"I need to do what I can.","TWN":"我會盡我所能。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"종종 그런 생각하곤 해.","JPN":"私はたまに思う。","ENG":"I often think about this.","TWN":"我時常會有那樣的想法。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"결국, 이 세상의 모든 것은 보이지 않는 실로 연결되어 있는 게 아닐까 하고 말이야.","JPN":"結局、この世のすべては見えない糸で繋がっているのではないかと。","ENG":"In the end, this world is connected by invisible threads, I think.","TWN":"最終，這個世界上的一切，是不是都被一根看不見的線連接在一起了？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그렇다면 역으로 세상을 바꾸기 위해서, 개인이 할 수 있는 건 하나뿐이겠지.","JPN":"なら、逆に世界を変えるために、個人ができるのはただ一つしかない。","ENG":"So, thinking about it backwards and how to change the world, there's only one thing an individual can do.","TWN":"那麼，為了改變世界，我個人能做的只有一件事。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"바로 자신과 연결된 다른 인연을 외면하지 않는 것.","JPN":"自分と繋がった絆から目を背けないこと。","ENG":"That is to not neglect the relationship one creates with others.","TWN":"那就是不要回避與自己相連的其他緣分。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그렇게 인연들이 조금씩 쌓이고, 또 쌓인다면…….","JPN":"そうやって絆を少しずつ積み重ねていけば……","ENG":"And as one builds relationships one after another...","TWN":"這樣一來，緣分會一點點積累，再積累……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그들이 베푼 선의가 쌓이고, 쌓인다면 정말로 세상을 바꿀 수 있을지도 모르니까.","JPN":"そして彼らの善意が積み重なっていけば、本当に世界を変えることができるかもしれないから。","ENG":"The good deeds that one gave will accumulate, and perhaps really change the world.","TWN":"如果每個人的善意能不斷疊加起來的話，真的有可能改變這個世界吧。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"어느정도 예상했던… 지극히 당신다운 대답이긴 하군요.","JPN":"ある程度は予想していた……極めてあなたらしい答えですね。","ENG":"That is... very much what someone like you would say, as expected.","TWN":"預料之中的回答……很像你的作風。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"하지만 지금 기적이 일어나 봉인을 틀어막는다 해도, 태엽을 감은 타기리온이 현실에 강림하는 건 시간 문제일 뿐입니다.","JPN":"しかし今奇跡が起きてまた封印したとしても、タギリオンのねじは巻かれました。現実に降臨するのはもはや時間の問題です。","ENG":"Even if, by some miracle, you stop the seal from breaking, Thagirion's spring has been wound. It's only a matter of time before she emerges into the Normalside.","TWN":"即使現在發生奇跡阻止封印解開，塔基里翁的降臨也只是時間問題。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇다고 남은 시간을 체념만 하며 보낼 순 없지 않겠나.","JPN":"だからと言って残っている時間をただ諦めて過ごすわけにはいかないだろう。","ENG":"That doesn't mean I should waste whatever precious time I have left.","TWN":"但總不想垂頭喪氣地等死吧。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신의 세계에 와일드카드는 많지만, 지금 당장 꺼낼 수 있는 건 없어요.","JPN":"あなたの世界にワイルドカードは多いですが、今使えるカードはないはずです。","ENG":"There are a lot of wildcards in your world, but none you can play right now.","TWN":"就算你的世界裡有很多幫手，但在這裡卻一個也派不上用場。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"늑대는 상처를 입어 제 실력을 발휘하지 못하고, 대적자는 빼앗은 마왕의 권능을 갈무리하고 있으며, 발키리는 기억을 되찾기 위해 아케론으로 향했죠.","JPN":"オオカミは怪我を負い戦力外になり、敵対者は奪った魔王の権能を収束しているところ、ヴァルキリーは記憶を取り戻すためにアケロンへ向かいましたね。","ENG":"The Wolf is wounded and not in her best shape to fight, the Antagonist is wrestling with the power of the Demon Lord that he stole, and the Valkyrie has headed to Acheron to retrieve her lost memories.","TWN":"狼受了傷，無法發揮出最佳狀態，敵對者正在消化他奪取的魔王之力，而女武神則前往阿刻戎尋回自己的記憶。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"타기리온에 대적할 운명인 아발론의 후손들과 시무르그의 파편 또한 침식으로부터 당장 주변의 인명을 지키기 위해 발이 묶여 있습니다.","JPN":"タギリオンに敵対する運命であるアバロンの末裔とシムルグの破片も同じく、周りの人々を侵食から守るために動けない状態です。","ENG":"The descendants of Avalon and the fragment of Simurgh, who were fated to fight Thagirion, are also tied up trying to protect people from Corruption.","TWN":"命中註定與塔基里翁對抗的阿瓦隆的後裔和西摩格的碎片，現在也只能忙著保護周圍人的安全。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신 혼자서 요술이라도 부릴 셈인가요?","JPN":"あなた一人で魔法でも使うつもりですか？","ENG":"So, are you planning on performing some kind of magic on your own?","TWN":"你一個人還能使出什麼花樣？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"나 혼자선 아무것도 바꿀 수 있는 게 없네.","JPN":"私一人では何も変えられない。","ENG":"There is nothing I can do alone to change anything.","TWN":"我一個人無法改變任何事情。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네도 알다시피, 평범한 인간이니까.","JPN":"君もご存じのとおり、私はただの人間だからね。","ENG":"As you know, I'm just an ordinary human.","TWN":"如你所見，我只是個普通人。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"아무리 뛰어난 해결사라고 해도, 혼자서 모든 것을 해결할 수는 없어.","JPN":"いくら立派な解決屋であっても、一人ですべてを解決することはできない。","ENG":"No matter how skilled one is as a problem solver, one can't solve everything on one's own.","TWN":"再優秀的問題解決者，也無法獨自解決所有的難題。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"경찰 같은 조직력이 없는, 나 같은 자문 탐정이라면 더욱 그렇지.","JPN":"警察のような組織のない、私のような諮問探偵ならなおさらだ。","ENG":"That's especially true for a consulting detective like me who has no organizational support, such as the police.","TWN":"像我這樣的顧問偵探，沒有員警那樣的組織能力，更是如此。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그렇기에 타인을 도와서, 인연을 만들어 두는 거라네.","JPN":"だからこそ他人を助け、絆を築いておくのだ。","ENG":"That is why I help people and build relationships.","TWN":"正因為這樣，我才會幫助他人，結下緣分。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"과거에 맺었던 인연들은, 틀림없이 미래의 다른 사건을 해결하는데 도움이 될 테니까.","JPN":"過去の絆は、きっと未来の他の事件を解決するのに役立つはずだから。","ENG":"The relationships we made in the past will undoubtedly become helpful in solving other cases in the future.","TWN":"過去結下的緣分，必定會對未來解決其他事件有所幫助。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"제가 지금 당신을 이곳에 가둬놓아도 별 의미는 없는 것 같네요.","JPN":"今あなたをここに閉じ込めておくのも大した意味はなさそうですね。","ENG":"It seems that there is no use keeping you in here right now.","TWN":"我覺得現在把你困在這裡也沒什麼意義。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"잠시 객석에서 일어나는 것 정도는 허락해드리죠.","JPN":"少しの間客席から立つことを許可しましょう。","ENG":"I shall grant you an intermission.","TWN":"也好，我允許你暫時離開觀眾席。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};